/**
 * Returns the audio file for a specific improved-replay turn
 * @summary Serve generated improved-replay audio
 */
export const getGetAudioUrl = (turnId: string) => {
  return `/api/audio/${turnId}`;
};

export const getAudio = async (
  turnId: string,
  options?: RequestInit,
): Promise<Blob> => {
  return customFetch<Blob>(getGetAudioUrl(turnId), {
    ...options,
    method: "GET",
  });
};

export const getGetAudioQueryKey = (turnId: string) => {
  return [`/api/audio/${turnId}`] as const;
};

export const getGetAudioQueryOptions = <
  TData = Awaited<ReturnType<typeof getAudio>>,
  TError = ErrorType<UnauthorizedResponse>,
>(
  turnId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAudio>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetAudioQueryKey(turnId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getAudio>>> = ({
    signal,
  }) => getAudio(turnId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!turnId,
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof getAudio>>, TError, TData> & {
    queryKey: QueryKey;
  };
};

export type GetAudioQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAudio>>
>;
export type GetAudioQueryError = ErrorType<UnauthorizedResponse>;

/**
 * @summary Serve generated improved-replay audio
 */

export function useGetAudio<
  TData = Awaited<ReturnType<typeof getAudio>>,
  TError = ErrorType<UnauthorizedResponse>,
>(
  turnId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAudio>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetAudioQueryOptions(turnId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
